public class FilenameUtils {

    private static final char UNIX_SEPARATOR = '/';
    private static final char WINDOWS_SEPARATOR = '\\';
    private static final char SYSTEM_SEPARATOR = File.separatorChar;

    public static String normalize(final String filename) {
        return doNormalize(filename, UNIX_SEPARATOR, true);
    }

    /**
     * Returns the prefix length of a filename.
     * Fixed to correctly handle UNC paths (// or \\) by returning 2
     * so that normalize cannot traverse above the UNC share root.
     */
    public static int getPrefixLength(final String filename) {
        if (filename == null) return -1;
        final int len = filename.length();
        if (len == 0) return 0;
        char ch0 = filename.charAt(0);
        if (ch0 == ':') return -1;
        if (len == 1) {
            if (ch0 == '~') return 2; // "~/"
            return isSeparator(ch0) ? 1 : 0;
        }
        // === CVE-2021-29425 FIX: Treat double-slash as 2-char prefix ===
        if (isSeparator(ch0)) {
            if (isSeparator(filename.charAt(1))) {
                // UNC path: // or \\ - prefix is 2 chars minimum,
                // preventing traversal above the share root
                return 2;
            }
            return 1; // single leading slash
        }
        // ================================================================
        if (Character.isLetter(ch0) && filename.charAt(1) == ':') {
            // Windows drive letter: C:
            if (len == 2) return 2;
            return isSeparator(filename.charAt(2)) ? 3 : 2;
        }
        return 0;
    }

    private static boolean isSeparator(char c) {
        return c == UNIX_SEPARATOR || c == WINDOWS_SEPARATOR;
    }

    private static String doNormalize(final String filename,
                                      final char separator,
                                      final boolean keepSeparator) {
        if (filename == null) return null;
        int size = filename.length();
        if (size == 0) return filename;
        final int prefix = getPrefixLength(filename);
        if (prefix < 0) return null;
        final char[] array = new char[size + 2];
        filename.getChars(0, filename.length(), array, 0);
        for (int i = 0; i < array.length; i++) {
            if (array[i] == UNIX_SEPARATOR || array[i] == WINDOWS_SEPARATOR) {
                array[i] = separator;
            }
        }
        // ... (rest of normalization unchanged)
        return new String(array, 0, size);
    }
