import org.apache.commons.compress.archivers.zip.ZipArchiveInputStream;
import java.io.EOFException;

public class ZipArchiveInputStream extends ArchiveInputStream {

    private long bytesReadFromStream = 0;
    private ZipArchiveEntry current;

    @Override
    public int read(byte[] buffer, int offset, int length) throws IOException {
        if (closed) throw new IOException("The stream is closed");
        if (hitCentralDirectory) return -1;
        if (current == null) return -1;

        if (current.getMethod() == ZipEntry.STORED) {
            long remaining = current.getSize() - bytesReadFromStream;
            if (remaining <= 0) return -1;

            int toRead = (int) Math.min(remaining, length);
            int read = in.read(buffer, offset, toRead);

            // === CVE-2018-11771 FIX ===
            // If the underlying stream is exhausted before we read all expected
            // bytes, the archive is corrupt/truncated. Throw EOFException so
            // callers cannot loop forever waiting for more data.
            if (read == -1) {
                throw new EOFException("Truncated ZIP file: expected "
                    + remaining + " more bytes for entry "
                    + current.getName());
            }
            // ==========================

            if (read > 0) bytesReadFromStream += read;
            return read;
        }
        return -1;
    }
}

