import org.opensaml.saml2.core.Response;

public class CombinedValidator implements SAMLProtocolResponseValidator {

    @Override
    public void validateSamlResponse(
            Response samlResponse,
            boolean postBinding) throws WSSecurityException {

        validateResponseSignature(samlResponse);

        // === CVE-2015-5253 FIX: Each Assertion must be individually signed ===
        // unless the entire Response itself is signed (in which case tampering
        // would invalidate the Response signature).
