        for (Assertion assertion : samlResponse.getAssertions()) {
            boolean assertionIsSigned = (assertion.getSignature() != null);

            if (!responseIsSigned && !assertionIsSigned) {
                // Neither the Response nor this Assertion is signed:
                // this is an XSW attack candidate - reject it.
                throw new WSSecurityException(
                    WSSecurityException.FAILED_CHECK,
                    "samlTokenUnsigned",
                    null,
                    null);
            }

            if (assertionIsSigned) {
                // Validate the individual assertion signature
                validateAssertionSignature(assertion);
            }

            processAssertion(assertion);
        }
        // =====================================================================
