import java.nio.ByteBuffer;
import java.nio.CharBuffer;
import java.nio.charset.Charset;
import java.nio.charset.CharsetEncoder;
import java.nio.charset.CoderResult;
import java.nio.charset.CodingErrorAction;

public class NioZipEncoding implements ZipEncoding {

    private final Charset charset;

    @Override
    public ByteBuffer encode(final String name) {
        // === CVE-2019-12402 FIX: Use REPLACE action for malformed input ===
        // Configure encoder to replace malformed characters instead of
        // returning an error result that would cause an infinite loop.
        final CharsetEncoder enc = charset.newEncoder()
            .onMalformedInput(CodingErrorAction.REPLACE)
            .onUnmappableCharacter(CodingErrorAction.REPLACE);
        // ====================================================================

        CharBuffer cb = CharBuffer.wrap(name);
        ByteBuffer out = ByteBuffer.allocate((int)(name.length() * enc.averageBytesPerChar()));

        while (cb.hasRemaining()) {
            final CoderResult result = enc.encode(cb, out, false);

            if (result.isUnderflow()) {
                break;
            } else if (result.isOverflow()) {
                out = ZipEncodingHelper.growBuffer(out, out.capacity() + 2);
            } else if (result.isError()) {
                // With REPLACE action this branch should not be reached,
                // but as a safety net: advance past the bad character
                // to guarantee the loop always makes progress.
                result.throwException(); // Will not throw for REPLACE action
            }
        }

        enc.encode(cb, out, true); // flush
        enc.flush(out);
        return out;
    }
}

