import org.springframework.web.bind.annotation.*;
import org.springframework.http.ResponseEntity;
import org.springframework.http.HttpStatus;
import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.net.*;
import java.util.*;

@RestController
public class FetchController {

    // Only these domains are allowed to be fetched
    private static final Set<String> ALLOWED_DOMAINS = new HashSet<>(Arrays.asList(
        "api.trusted-partner.com",
        "cdn.myapp.com"
    ));

    // Private/reserved CIDR ranges that must never be contacted
    private static final List<long[]> BLOCKED_RANGES = Arrays.asList(
        new long[]{ipToLong("10.0.0.0"),      ipToLong("10.255.255.255")},
        new long[]{ipToLong("172.16.0.0"),     ipToLong("172.31.255.255")},
        new long[]{ipToLong("192.168.0.0"),    ipToLong("192.168.255.255")},
        new long[]{ipToLong("127.0.0.0"),      ipToLong("127.255.255.255")},
        new long[]{ipToLong("169.254.0.0"),    ipToLong("169.254.255.255")},
        new long[]{ipToLong("100.64.0.0"),     ipToLong("100.127.255.255")}
    );

    @GetMapping("/api/fetch")
    public ResponseEntity<String> fetchContent(@RequestParam String url) {
        try {
            URL target = new URL(url);

            // 1. Only allow HTTPS scheme
            if (!"https".equalsIgnoreCase(target.getProtocol())) {
                return ResponseEntity.status(HttpStatus.BAD_REQUEST)
                    .body("Only HTTPS URLs are permitted");
            }

            // 2. Validate host against allowlist
            String host = target.getHost().toLowerCase();
            if (!ALLOWED_DOMAINS.contains(host)) {
                return ResponseEntity.status(HttpStatus.FORBIDDEN)
                    .body("Domain not in allowlist");
            }

            // 3. Resolve IP and block private ranges
            InetAddress addr = InetAddress.getByName(host);
            long ipLong = ipToLong(addr.getHostAddress());
            for (long[] range : BLOCKED_RANGES) {
                if (ipLong >= range[0] && ipLong <= range[1]) {
                    return ResponseEntity.status(HttpStatus.FORBIDDEN)
                        .body("Target resolves to a private/reserved IP");
                }
            }

            // 4. Perform the request with no redirects to prevent redirect-based bypass
            HttpURLConnection conn = (HttpURLConnection) target.openConnection();
            conn.setRequestMethod("GET");
            conn.setConnectTimeout(5000);
            conn.setReadTimeout(5000);
            conn.setInstanceFollowRedirects(false); // No redirect following

            BufferedReader reader = new BufferedReader(
                new InputStreamReader(conn.getInputStream()));
            StringBuilder response = new StringBuilder();
            String line;
            while ((line = reader.readLine()) != null) {
                response.append(line).append("\n");
                if (response.length() > 4096) break; // limit response size
            }
            reader.close();
            return ResponseEntity.ok(response.substring(0, Math.min(500, response.length())));

        } catch (Exception e) {
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                .body("Request failed");
        }
    }

    private static long ipToLong(String ip) {
        String[] parts = ip.split("\\.");
        long result = 0;
        for (String part : parts) result = result * 256 + Long.parseLong(part);
        return result;
    }
}

