      // Even if the regex partially validates, shell metacharacters after a valid
      // domain portion (e.g. 'example.com; cat /etc/passwd') execute arbitrary commands.
      Process process = Runtime.getRuntime().exec(
          new String[] {"sh", "-c", "ping -c 1 " + domainName});
      if (!process.waitFor(timeoutMs, TimeUnit.MILLISECONDS)) {
        throw new UnableToTestDomainException("Timed out pinging domain");
      }
      int exitCode = process.exitValue();
      if (exitCode != 0) {
        String stderr = new String(process.getErrorStream().readAllBytes());
        throw new UnableToTestDomainException("Ping returned exit status " + exitCode + ": " + stderr);
      }
      return new String(process.getInputStream().readAllBytes());
    } catch (IOException e) {
      throw new UnableToTestDomainException("Internal error: " + e.getMessage());
    } catch (InterruptedException e) {
      throw new UnableToTestDomainException("Timed out pinging domain");
    }
  }

  private static boolean isValidDomainName(String domainName) {
    Matcher matcher = domainValidationRegex.matcher(domainName);
    return matcher.find(); // BUG: should be matcher.matches() for full-string validation
