package com.datadoghq.workshops.samplevulnerablejavaapp.service;

import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.*;
import org.springframework.stereotype.Service;
import org.springframework.web.client.RestTemplate;

import java.net.InetAddress;
import java.net.URI;
import java.util.Set;

@Service
public class WebsiteTestService {
    @Autowired
    private RestTemplate rest;

    private static final Set<String> ALLOWED_SCHEMES = Set.of("http", "https");

    public String testWebsite(WebsiteTestRequest request) {
        try {
            // FIX (SSRF): Validate the URL scheme and reject private/loopback IP ranges.
            URI uri = URI.create(request.url);
            String scheme = uri.getScheme() == null ? "" : uri.getScheme().toLowerCase();
            if (!ALLOWED_SCHEMES.contains(scheme)) {
                throw new IllegalArgumentException("URL scheme '" + scheme + "' is not permitted");
            }
            InetAddress address = InetAddress.getByName(uri.getHost());
            if (address.isLoopbackAddress() || address.isSiteLocalAddress()
                    || address.isLinkLocalAddress() || address.isAnyLocalAddress()) {
                throw new IllegalArgumentException("Requests to internal addresses are forbidden");
            }

            HttpHeaders headers = new HttpHeaders();
            if (request.customHeaderKey != null && !request.customHeaderKey.isEmpty()) {
                // FIX (Header Injection): Reject keys or values containing CR or LF.
                if (containsCRLF(request.customHeaderKey) || containsCRLF(request.customHeaderValue)) {
                    throw new IllegalArgumentException("Header key or value contains illegal characters");
                }
                headers.set(request.customHeaderKey, request.customHeaderValue);
            }

            HttpEntity<String> entity = new HttpEntity<>("", headers);
            return this.rest.exchange(uri, HttpMethod.GET, entity, String.class).getBody();
        } catch (HttpClientErrorException | HttpServerErrorException e) {
            return "URL returned status code: " + e.getStatusCode();
        } catch (IllegalArgumentException e) {
            return "Request blocked: " + e.getMessage();
        } catch (Exception e) {
            return "Error: " + e.getMessage();
        }
    }

    private static boolean containsCRLF(String value) {
        return value != null && (value.contains("\r") || value.contains("\n"));
    }
}

